    41→// Get request host from the request header map, removing the port if the port
    42→// does not match the scheme, or if port is provided.
    43→absl::string_view processRequestHost(const Http::RequestHeaderMap& headers,
    44→                                     absl::string_view new_scheme, absl::string_view new_port) {
    45→
    46→  absl::string_view request_host = headers.getHostValue();
    47→  size_t host_end;
    48→  if (request_host.empty()) {
    49→    return request_host;
    50→  }
    51→  // Detect if IPv6 URI
    52→  if (request_host[0] == '[') {
    53→    host_end = request_host.rfind("]:");
    54→    if (host_end != absl::string_view::npos) {
    55→      host_end += 1; // advance to :
    56→    }
    57→  } else {
    58→    host_end = request_host.rfind(':');
    59→  }
    60→
    61→  if (host_end != absl::string_view::npos) {
    62→    absl::string_view request_port = request_host.substr(host_end);
    63→    // In the rare case that X-Forwarded-Proto and scheme disagree (say http URL over an HTTPS
    64→    // connection), do port stripping based on X-Forwarded-Proto so http://foo.com:80 won't
    65→    // have the port stripped when served over TLS.
    66→    absl::string_view request_protocol = headers.getForwardedProtoValue();
    67→    bool remove_port = !new_port.empty();
    68→
    69→    if (new_scheme != request_protocol) {
    70→      remove_port |= Http::Utility::schemeIsHttps(request_protocol) && request_port == ":443";
    71→      remove_port |= Http::Utility::schemeIsHttp(request_protocol) && request_port == ":80";
    72→    }
    73→
    74→    if (remove_port) {
    75→      return request_host.substr(0, host_end);
    76→    }
    77→  }
    78→
    79→  return request_host;
    80→}
