   105→absl::Status
   106→validateCustomSettingsParameters(const envoy::config::core::v3::Http2ProtocolOptions& options) {
   107→  std::vector<std::string> parameter_collisions, custom_parameter_collisions;
   108→  absl::node_hash_set<SettingsEntry, SettingsEntryHash, SettingsEntryEquals> custom_parameters;
   109→  // User defined and named parameters with the same SETTINGS identifier can not both be set.
   110→  for (const auto& it : options.custom_settings_parameters()) {
   111→    ASSERT(it.identifier().value() <= std::numeric_limits<uint16_t>::max());
   112→    // Check for custom parameter inconsistencies.
   113→    const auto result = custom_parameters.insert(
   114→        {static_cast<uint16_t>(it.identifier().value()), it.value().value()});
   115→    if (!result.second) {
   116→      if (result.first->value != it.value().value()) {
   117→        custom_parameter_collisions.push_back(
   118→            absl::StrCat("0x", absl::Hex(it.identifier().value(), absl::kZeroPad2)));
   119→        // Fall through to allow unbatched exceptions to throw first.
   120→      }
   121→    }
   122→    switch (it.identifier().value()) {
   123→    case http2::adapter::ENABLE_PUSH:
   124→      if (it.value().value() == 1) {
   125→        return absl::InvalidArgumentError(
   126→            "server push is not supported by Envoy and can not be enabled via a "
   127→            "SETTINGS parameter.");
   128→      }
   129→      break;
   130→    case http2::adapter::ENABLE_CONNECT_PROTOCOL:
   131→      // An exception is made for `allow_connect` which can't be checked for presence due to the
   132→      // use of a primitive type (bool).
   133→      return absl::InvalidArgumentError(
   134→          "the \"allow_connect\" SETTINGS parameter must only be configured "
   135→          "through the named field");
   136→    case http2::adapter::HEADER_TABLE_SIZE:
   137→      if (options.has_hpack_table_size()) {
   138→        parameter_collisions.push_back("hpack_table_size");
   139→      }
   140→      break;
   141→    case http2::adapter::MAX_CONCURRENT_STREAMS:
   142→      if (options.has_max_concurrent_streams()) {
   143→        parameter_collisions.push_back("max_concurrent_streams");
   144→      }
